import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Pollutant {
  name: string;
  value: number;
}

interface AirQualityData {
  location: string;
  currentIndex: number;
  qualityLevel: string;
  pollutants: Pollutant[];
}

export default function Widget() {
  const airQualityData = response.data as AirQualityData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Air Quality Index
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {airQualityData.currentIndex}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {airQualityData.qualityLevel}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1, color: '#4CAF50' }}>
              Location: {airQualityData.location}
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {airQualityData.pollutants.map((pollutant, index) => (
                <Chip
                  key={index}
                  label={`${pollutant.name}: ${pollutant.value}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: airQualityData.pollutants.map(p => p.value),
                  label: airQualityData.pollutants.map(p => p.name),
                  color: ['#FF8A65', '#4DB6AC', '#BA68C8'],
                },
              ]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <PieChart />
              </g>
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
